using System;
using System.Collections.Generic;
using System.Threading;

public class EventProcessor : IDisposable
{
    private readonly ManualResetEvent _newEvent = new ManualResetEvent(false);
    private readonly Queue<string> _queue = new Queue<string>();
    private Thread? _thread;
    private readonly object _lock = new object();
    private readonly CancellationTokenSource _cts = new CancellationTokenSource();

    public void Start()
    {
        _thread = new Thread(RunLoop);
        _thread.Start();
    }

    private void RunLoop()
    {
        var token = _cts.Token;
        var handles = new WaitHandle[] { _newEvent, token.WaitHandle };

        while (!token.IsCancellationRequested)
        {
            // WaitAny wakes on either a new event OR cancellation — replaces
            // the old WaitOne() that required Thread.Interrupt to break out of.
            int signaled = WaitHandle.WaitAny(handles);

            if (signaled == 1) // cancellation token fired
                break;

            _newEvent.Reset();

            string? item = null;
            lock (_lock)
            {
                if (_queue.Count > 0)
                    item = _queue.Dequeue();
            }

            if (item is not null)
                Handle(item);
        }
    }

    public void Enqueue(string item)
    {
        lock (_lock) { _queue.Enqueue(item); }
        _newEvent.Set();
    }

    public void Stop()
    {
        _cts.Cancel();        // cooperatively signals the loop to exit
        _thread?.Join(5000);  // wait for graceful shutdown
    }

    public void Dispose()
    {
        Stop();
        _cts.Dispose();
        _newEvent.Dispose();
    }

    private void Handle(string item)
    {
        // application logic here
    }
}

